import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.C58al07P.js";const p=JSON.parse('{"title":"First steps","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/first-steps.md","filePath":"en/guide/first-steps.md"}'),s={name:"en/guide/first-steps.md"};function n(l,e,r,c,h,u){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="first-steps" tabindex="-1">First steps <a class="header-anchor" href="#first-steps" aria-label="Permalink to &quot;First steps&quot;">​</a></h1><p>This guide walks you through your first minutes with Nid.</p><hr><h2 id="create-your-account" tabindex="-1">Create your account <a class="header-anchor" href="#create-your-account" aria-label="Permalink to &quot;Create your account&quot;">​</a></h2><p>Open the application in your browser (default: <a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a>).</p><p>Two account creation options are available:</p><h3 id="local-account" tabindex="-1">Local account <a class="header-anchor" href="#local-account" aria-label="Permalink to &quot;Local account&quot;">​</a></h3><ol><li>Click <strong>Create an account</strong></li><li>Enter your email and a password (minimum 8 characters)</li><li>Click <strong>Sign up</strong></li></ol><h3 id="sign-in-with-google-sso" tabindex="-1">Sign in with Google (SSO) <a class="header-anchor" href="#sign-in-with-google-sso" aria-label="Permalink to &quot;Sign in with Google (SSO)&quot;">​</a></h3><ol><li>Click <strong>Sign in with Google</strong></li><li>Choose your Google account</li><li>Grant access</li></ol><p>Your Google name and avatar are retrieved automatically.</p><blockquote><p>📸 <em>Suggested screenshot: login page with both options (form + Google SSO button)</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Account merging</p><p>If you first create a local account and then sign in with Google using the same email, both accounts are automatically merged.</p></div><hr><h2 id="become-an-administrator" tabindex="-1">Become an administrator <a class="header-anchor" href="#become-an-administrator" aria-label="Permalink to &quot;Become an administrator&quot;">​</a></h2><p>The first user must be promoted to administrator. Three options:</p><h3 id="option-a-—-automatically-recommended" tabindex="-1">Option A — Automatically (recommended) <a class="header-anchor" href="#option-a-—-automatically-recommended" aria-label="Permalink to &quot;Option A — Automatically (recommended)&quot;">​</a></h3><p>Before creating your account, add the following to the <code>.env</code> file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ADMIN_EMAIL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your@email.com</span></span></code></pre></div><p>The user who signs up with this email automatically gets the admin role.</p><h3 id="option-b-—-in-the-database" tabindex="-1">Option B — In the database <a class="header-anchor" href="#option-b-—-in-the-database" aria-label="Permalink to &quot;Option B — In the database&quot;">​</a></h3><p>If your account already exists:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> postgres</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> psql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -U</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gmailmanager</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gmailmanager</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;UPDATE users SET role = &#39;admin&#39; WHERE email = &#39;your@email.com&#39;;&quot;</span></span></code></pre></div><p>Log out and log back in for the new role to take effect.</p><h3 id="option-c-—-via-the-interface" tabindex="-1">Option C — Via the interface <a class="header-anchor" href="#option-c-—-via-the-interface" aria-label="Permalink to &quot;Option C — Via the interface&quot;">​</a></h3><p>An existing administrator can promote other users from <strong>Administration</strong> → <strong>Users</strong> → <strong>Change role</strong>.</p><div class="info custom-block"><p class="custom-block-title">Difference between roles</p><ul><li><strong>User</strong>: full access to their own data (emails, archives, rules, etc.)</li><li><strong>Administrator</strong>: access to all users&#39; data + quota and role management</li></ul></div><hr><h2 id="connect-a-gmail-account" tabindex="-1">Connect a Gmail account <a class="header-anchor" href="#connect-a-gmail-account" aria-label="Permalink to &quot;Connect a Gmail account&quot;">​</a></h2><p>Once logged in, you need to link your Gmail mailbox so the application can access it.</p><ol><li>Go to <strong>Settings</strong> (⚙️ icon in the sidebar)</li><li>In the <strong>Gmail accounts</strong> section, click <strong>Connect a Gmail account</strong></li><li>Google will ask you to authorize three types of access: <ul><li>Reading and modifying your emails</li><li>Managing your labels</li><li>Reading your email address</li></ul></li><li>Click <strong>Allow</strong></li><li>You are redirected to Settings with a confirmation</li></ol><blockquote><p>📸 <em>Suggested screenshot: Settings page with the &quot;Connect a Gmail account&quot; button and the list of connected accounts</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">Google warning screen</p><p>If your Google Cloud project is in &quot;Test&quot; mode, a warning screen will appear. Click <strong>Advanced settings</strong> → <strong>Go to nid (unsafe)</strong>. This is normal for personal self-hosted use.</p></div><h3 id="adding-more-gmail-accounts" tabindex="-1">Adding more Gmail accounts <a class="header-anchor" href="#adding-more-gmail-accounts" aria-label="Permalink to &quot;Adding more Gmail accounts&quot;">​</a></h3><p>Repeat the process to connect additional accounts. You can manage up to 5 accounts by default (configurable by the administrator).</p><p>Each account appears in the <strong>account selector</strong> at the top of the sidebar. Select an account to display its data across all sections of the application.</p><blockquote><p>📸 <em>Suggested screenshot: Gmail account selector in the sidebar with multiple accounts listed</em></p></blockquote><hr><h2 id="explore-the-dashboard" tabindex="-1">Explore the Dashboard <a class="header-anchor" href="#explore-the-dashboard" aria-label="Permalink to &quot;Explore the Dashboard&quot;">​</a></h2><p>After connecting your Gmail, the <strong>Dashboard</strong> automatically loads your mailbox statistics:</p><ul><li><strong>Top senders</strong>: who sends you the most emails and takes up the most space</li><li><strong>Largest emails</strong>: quickly identify emails to delete first</li><li><strong>Timeline</strong>: email volume evolution by month</li><li><strong>Label distribution</strong>: distribution of your Gmail labels</li></ul><blockquote><p>📸 <em>Suggested screenshot: full Dashboard page with the 4 charts</em></p></blockquote><p>The initial loading may take a few seconds depending on the size of your mailbox.</p><hr><h2 id="your-first-cleanup-operation" tabindex="-1">Your first cleanup operation <a class="header-anchor" href="#your-first-cleanup-operation" aria-label="Permalink to &quot;Your first cleanup operation&quot;">​</a></h2><p>Try a first bulk deletion operation:</p><ol><li>Open <strong>My emails</strong> in the sidebar</li><li>Use the search bar to filter (e.g.: <code>from:newsletter@example.com</code>)</li><li>Check the box at the top of the table to select all results</li><li>Click <strong>Delete (trash)</strong> in the action bar</li><li>A <strong>job</strong> is created — a modal window shows real-time progress</li></ol><blockquote><p>📸 <em>Suggested screenshot: My emails page with selected emails and the bulk action bar visible</em></p></blockquote><blockquote><p>📸 <em>Suggested screenshot: job progress modal with progress bar</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Trash vs permanent deletion</p><p>Deletion sends emails to the <strong>Gmail trash</strong> (recoverable for 30 days). Permanent deletion is irreversible — use it with caution.</p></div><hr><h2 id="your-first-archive" tabindex="-1">Your first archive <a class="header-anchor" href="#your-first-archive" aria-label="Permalink to &quot;Your first archive&quot;">​</a></h2><p>To back up emails to your NAS:</p><ol><li>In <strong>My emails</strong>, filter the emails to archive</li><li>Select them or click <strong>Archive all</strong> to archive all results</li><li>An archiving job is created</li><li>The EML files are saved to the archives folder</li></ol><p>Then check the <strong>Archives</strong> section to find your archived emails with full-text search.</p><blockquote><p>📸 <em>Suggested screenshot: Archives section with the search bar and the list of archived emails</em></p></blockquote><hr><h2 id="what-s-next" tabindex="-1">What&#39;s next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next?&quot;">​</a></h2><p>Now that you are up and running, explore the other features:</p><ul><li><a href="./rules.html"><strong>Automatic rules</strong></a> — automate recurring cleanup</li><li><a href="./newsletters.html"><strong>Newsletters</strong></a> — identify and clean up newsletters in bulk</li><li><a href="./analytics.html"><strong>Analytics</strong></a> — understand your email habits</li><li><a href="./settings.html"><strong>Settings</strong></a> — enable 2FA, configure webhooks, change the language</li></ul>`,60)])])}const g=t(s,[["render",n]]);export{p as __pageData,g as default};
